function getStdLength(category, clubLabel, brand, model) {
  if (category === 'driver') return STD_LENGTHS.driver;
  if (category === 'putter') return STD_LENGTHS.putter;
  if (category === 'wedge') {
    const loft = parseFloat(clubLabel);
    return !isNaN(loft) ? STD_LENGTHS.wedge(loft) : 35.25;
  }
  if (category === 'fairway') return STD_LENGTHS.fairway[clubLabel] || 42;
  if (category === 'hybrid') return STD_LENGTHS.hybrid[clubLabel] || 39;
  if (category === 'irons') {
    var brandLengths = STD_LENGTHS.ironByBrand[brand];
    if (brandLengths && brandLengths[model] && brandLengths[model][clubLabel] !== undefined) {
      return brandLengths[model][clubLabel];
    }
    return STD_LENGTHS.ironGeneric[clubLabel] || 37;
  }
  return '';
}
