// Universal spec lookup for any club type + model name
// Returns { loft, lie, length } or null
function lookupClubSpec(clubType, modelStr) {
  if (!clubType || !modelStr) return null;
  const upper = modelStr.toUpperCase();

  if (clubType === 'Driver') {
    for (const d of DRIVER_SPECS) {
      if (upper.includes(d.model.toUpperCase()) || upper === (d.brand + ' ' + d.model).toUpperCase()) {
        return { loft: d.lofts[0] + '°', lie: d.lie + '°', length: getStdLength('driver') + '"', info: d.brand + ' ' + d.model };
      }
    }
  } else if (clubType === 'Putter') {
    for (const p of PUTTER_SPECS) {
      if (upper.includes(p.model.toUpperCase()) || upper === (p.brand + ' ' + p.model).toUpperCase()) {
        return { loft: p.loft + '°', lie: p.lie + '°', length: (p.length || 34) + '"', info: p.brand + ' ' + p.model };
      }
    }
  } else if (['3W','5W','7W','9W','3HL','4W'].includes(clubType)) {
    for (const fw of FAIRWAY_SPECS) {
      if (upper.includes(fw.model.toUpperCase()) || upper === (fw.brand + ' ' + fw.model).toUpperCase()) {
        const cfg = fw.configs[clubType];
        if (cfg) return { loft: cfg.loft + '°', lie: cfg.lie + '°', length: (getStdLength('fairway', clubType) || 42) + '"', info: fw.brand + ' ' + fw.model };
      }
    }
  } else if (['2H','3H','4H','5H','6H','7H'].includes(clubType)) {
    for (const h of HYBRID_SPECS) {
      if (upper.includes(h.model.toUpperCase()) || upper === (h.brand + ' ' + h.model).toUpperCase()) {
        const cfg = h.configs[clubType];
        if (cfg) return { loft: cfg.loft + '°', lie: cfg.lie + '°', length: (getStdLength('hybrid', clubType) || 39) + '"', info: h.brand + ' ' + h.model };
      }
    }
  }
  return null;
}
